function campaignWizardRenderGiftStepHtml({ d, tpl, stepNo }) {
  const th = campaignGiftThresholdLabel(tpl);
  const isQtyGift = campaignIsQtyGiftTemplate(tpl);
  const qtyGiftDisplayWay = campaignQtyGiftDisplayWay(d, tpl);
  const qtyGiftDataWay = campaignQtyGiftDataWay(d, tpl);
  const thStep = isQtyGift ? "1" : "0.01";
  const thMin = isQtyGift ? "1" : "0";
  d.giftScope = d.giftScope || {};
  d.giftScope.single = d.giftScope.single || { keyword: "", tab: "goods", goods: [], categories: [], brands: [], excludeGoods: [], excludeCategories: [] };
  d.giftScope.multiPurchase = d.giftScope.multiPurchase || { isAll: "否", threshold: "", keyword: "", tab: "goods", goods: [], categories: [], brands: [], excludeGoods: [], excludeCategories: [] };
  if (!Array.isArray(d.giftScope.multiGifts)) d.giftScope.multiGifts = [];
  if (!Array.isArray(d.giftScope.rewardGroups)) d.giftScope.rewardGroups = [];
  const gs = d.giftScope;
  const isAmountGift = campaignIsAmountGiftTemplate(tpl) && !campaignIsVoucherGiftTemplate(tpl);
  if (isAmountGift) {
    const promoGoodsJoin = String(gs.promoGoodsJoin || (String(gs.mutex || "否") === "是" ? "否" : "是"));
    const giftCondition = String(gs.giftCondition || "金额");
    const purchaseTypeAllowed = ["单品", "多组", "整单", "全场"];
    const purchaseTypeRaw = String(gs.purchaseType || "单品");
    const purchaseTypeTmp = purchaseTypeAllowed.includes(purchaseTypeRaw) ? purchaseTypeRaw : "单品";
    const purchaseType = purchaseTypeTmp === "全场" ? "整单" : purchaseTypeTmp;
    const purchaseScope = String(gs.purchaseScope || "商品");
    const giftTypeNorm = campaignGiftAmountGiftType(gs);
    const giftTypeAllow = ["本品", "它品"];
    const giftTypeRaw = giftTypeAllow.includes(String(gs.giftType || "")) ? String(gs.giftType || "") : giftTypeNorm;
    const mode = (String(gs.mode || "") === "阶梯" || String(gs.mode || "") === "倍数") ? String(gs.mode || "") : "阶梯";
    gs.promoGoodsJoin = promoGoodsJoin;
    gs.giftCondition = giftCondition;
    gs.purchaseType = purchaseType;
    gs.purchaseScope = purchaseScope;
    gs.giftType = giftTypeRaw;
    gs.mode = mode;
    gs.giftWay = campaignGiftAmountGiftTypeToWay(campaignGiftAmountGiftType(gs));
    gs.mutex = promoGoodsJoin === "否" ? "是" : "否";
    gs.purchaseRange = "单组";
    const opt = (list, v) => (list || []).map((x) => `<option value="${escapeHtml(x)}" ${String(v) === String(x) ? "selected" : ""}>${escapeHtml(x)}</option>`).join("");
    const conditionHtml = `
      <div class="combo-camp-form__row combo-camp-form__row--4">
        <div class="field">
          <div class="field__label"><span class="req">*</span>促销商品是否参与</div>
          <select class="select" data-cw="giftScope" data-field="promoGoodsJoin">${opt(["是", "否"], promoGoodsJoin)}</select>
        </div>
        <div class="field">
          <div class="field__label"><span class="req">*</span>满赠条件</div>
          <select class="select" data-cw="giftScope" data-field="giftCondition">${opt(["金额", "数量"], giftCondition)}</select>
        </div>
        <div class="field">
          <div class="field__label"><span class="req">*</span>购买类型</div>
          <select class="select" data-cw="giftScope" data-field="purchaseType">${opt(["单品", "多组", "整单"], purchaseType)}</select>
        </div>
        <div class="field">
          <div class="field__label"><span class="req">*</span>购买范围</div>
          <select class="select" data-cw="giftScope" data-field="purchaseScope">${opt(["商品", "类别", "品牌", "全场"], purchaseScope)}</select>
        </div>
      </div>
    `;
    const purchaseTypeNorm = campaignGiftPurchaseTypeNorm(purchaseType);
    const isCategorySpecial = campaignAmountGiftIsCategorySpecial(gs);
    const isBrandSpecial = campaignAmountGiftIsBrandSpecial(gs);
    const showBuyTable = giftCondition === "金额" && (purchaseTypeNorm === "单品" || purchaseTypeNorm === "多品" || purchaseTypeNorm === "全场" || purchaseTypeNorm === "买A送A/B") && (purchaseScope === "商品" || purchaseScope === "全场" || isCategorySpecial || isBrandSpecial);
    const isMultiGroupGoods = giftCondition === "金额" && String(purchaseType || "") === "多组" && String(purchaseScope || "") === "商品";
    const isMultiGroupCategory = giftCondition === "金额" && String(purchaseType || "") === "多组" && String(purchaseScope || "") === "类别";
    const isMultiGroupBrand = giftCondition === "金额" && String(purchaseType || "") === "多组" && String(purchaseScope || "") === "品牌";
    const isMultiGroupAll = giftCondition === "金额" && String(purchaseType || "") === "多组" && String(purchaseScope || "") === "全场";
    const isMultiGroupDual = isMultiGroupGoods || isMultiGroupCategory || isMultiGroupBrand || isMultiGroupAll;
    const buyTabRaw = (AppState.ui.campaignWizard.giftBuyTab || (gs.single && gs.single.tab) || (isMultiGroupAll ? "excludeGoods" : (isCategorySpecial ? "categories" : (isBrandSpecial ? "brands" : "goods"))));
    const buyTab = isMultiGroupAll
      ? "excludeGoods"
      : isCategorySpecial
      ? (["categories", "excludeCategories", "excludeGoods"].includes(String(buyTabRaw)) ? buyTabRaw : "categories")
      : (isBrandSpecial
        ? (["brands", "excludeGoods"].includes(String(buyTabRaw)) ? buyTabRaw : "brands")
        : "goods");
    AppState.ui.campaignWizard.giftBuyTab = buyTab;
    gs.single.tab = buyTab;
    const isExcludeGoodsTab = buyTab === "excludeGoods";
    const isExcludeCategoriesTab = buyTab === "excludeCategories";
    const isBrandTab = buyTab === "brands";
    const queryPlaceholder = isCategorySpecial
      ? (isExcludeGoodsTab ? "请输入商品编码、条码、名称" : (isMultiGroupCategory && buyTab === "categories" ? "请输入商品编码、条码、名称" : "请输入类别编码、类别名称"))
      : isBrandSpecial
        ? "请输入商品编码、条码、名称"
      : "请输入商品编码、条码、名称";
    const selectText = isCategorySpecial
      ? (isExcludeGoodsTab ? "选商品" : "选类别")
      : isBrandSpecial
        ? (isExcludeGoodsTab ? "选商品" : "选品牌")
      : "选商品";
    const importText = isCategorySpecial
      ? (buyTab === "categories" ? "导入买赠信息" : (isExcludeCategoriesTab ? "导入排除类别" : "导入排除商品"))
      : isBrandSpecial
        ? (isBrandTab ? "导入买赠信息" : "导入排除商品")
      : (isMultiGroupGoods ? "导入买赠信息" : (isMultiGroupAll ? "导入商品" : "导入"));
    const removeText = isCategorySpecial
      ? (isExcludeGoodsTab ? "移除商品" : "移除类别")
      : isBrandSpecial
        ? (isExcludeGoodsTab ? "移除商品" : "移除品牌")
      : "移除商品";
    const tabsHtml = isMultiGroupAll
      ? `<div class="tabbar tabbar--underline" id="campGiftBuyTabs">
          <button class="tabbtn is-active" type="button" data-act="campGiftBuyTab" data-id="excludeGoods">排除商品</button>
        </div>`
      : isCategorySpecial
      ? `<div class="tabbar tabbar--underline" id="campGiftBuyTabs">
          <button class="tabbtn ${buyTab === "categories" ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="categories">购买类别</button>
          <button class="tabbtn ${buyTab === "excludeCategories" ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="excludeCategories">排除类别</button>
          <button class="tabbtn ${buyTab === "excludeGoods" ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="excludeGoods">排除商品</button>
        </div>`
      : isBrandSpecial
        ? `<div class="tabbar tabbar--underline" id="campGiftBuyTabs">
          <button class="tabbtn ${buyTab === "brands" ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="brands">购买品牌</button>
          <button class="tabbtn ${buyTab === "excludeGoods" ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="excludeGoods">排除商品</button>
        </div>`
      : "";
    const queryBarHtml = campaignWizardRenderQueryBar({
      tabsHtml,
      inputHtml: `<input class="input" data-cw="giftSingleScope" data-field="keyword" value="${escapeHtml(String((gs.single && gs.single.keyword) || ""))}" placeholder="${escapeHtml(queryPlaceholder)}" />`,
      actionsHtml: `
        <button class="btn btn--primary" type="button" data-act="campKeywordQuery" data-cw="giftSingleScope" data-field="keyword">查询</button>
        <button class="btn btn--primary" type="button" data-act="campGiftBuySelect">${selectText}</button>
        <button class="btn" type="button" data-act="campGiftBuyImport">${importText}</button>
        <button class="btn" type="button" data-act="campGiftBuyAdd">增加行</button>
        <button class="btn" type="button" data-act="campAgGiftRemoveGoods">${removeText}</button>
      `
    });
    const buyHtml = showBuyTable ? `${queryBarHtml}<div id="campGiftBuyTable"></div>` : `<div class="empty">当前组合暂无原型（原型演示）</div>`;
    const buyTitle = isMultiGroupGoods ? "商品信息" : "买赠信息";
    return `
      <div class="wizard-step" data-step="${escapeHtml(String(stepNo))}">
        <div class="combo-camp-panel">
          ${comboCampaignSectionHtml("条件范围", conditionHtml)}
          ${comboCampaignSectionHtml(buyTitle, buyHtml)}
          ${showBuyTable && isMultiGroupDual ? comboCampaignSectionHtml("条件设置", `<div id="campGiftCondTable"></div>`) : ""}
        </div>
      </div>
    `;
  }
  if (isQtyGift) gs.giftWay = qtyGiftDataWay;
  if (isQtyGift && qtyGiftDataWay === "本品") gs.purchaseRange = "单组";
  const pr = String(gs.purchaseRange || "单组");
  const scene = campaignGiftScenario(gs, tpl);
  const giftModeHint = isQtyGift && pr === "单组"
    ? "单组下，倍数与阶梯均可添加多条记录。"
    : "倍数仅允许一条记录；阶梯允许添加多条记录。";
  const qtyGiftOnlyGoods = isQtyGift;
  const allowGoodsTabs = ["goods"];
  const allowExcludeTabs = ["excludeGoods", "excludeCategories"];
  if (!allowGoodsTabs.includes(String((gs.single && gs.single.tab) || ""))) gs.single.tab = "goods";
  if (!allowGoodsTabs.includes(String((gs.multiPurchase && gs.multiPurchase.tab) || ""))) gs.multiPurchase.tab = "goods";
  if (!allowExcludeTabs.includes(String(AppState.ui.campaignWizard.giftBuyExcludeTab || ""))) AppState.ui.campaignWizard.giftBuyExcludeTab = "excludeGoods";
  if (!allowExcludeTabs.includes(String(AppState.ui.campaignWizard.giftPurchaseExcludeTab || ""))) AppState.ui.campaignWizard.giftPurchaseExcludeTab = "excludeGoods";

  const buyTabRaw = AppState.ui.campaignWizard.giftBuyTab || (gs.single && gs.single.tab) || "goods";
  const buyTab = allowGoodsTabs.includes(String(buyTabRaw || "")) ? buyTabRaw : "goods";
  const buyRangeOptions = ["participate"];
  if (scene.isLadder && !qtyGiftOnlyGoods) buyRangeOptions.push("exclude");
  if (scene.isSingle && scene.useRewardRangeTab) buyRangeOptions.push("reward");
  const buyRangeRaw = AppState.ui.campaignWizard.giftBuyRange || "participate";
  const buyRange = buyRangeOptions.includes(String(buyRangeRaw || "")) ? buyRangeRaw : "participate";
  AppState.ui.campaignWizard.giftBuyTab = buyTab;
  AppState.ui.campaignWizard.giftBuyRange = buyRange;
  gs.single.tab = buyTab;
  const purchaseTabRaw = AppState.ui.campaignWizard.giftPurchaseTab || (gs.multiPurchase && gs.multiPurchase.tab) || "goods";
  const purchaseTab = allowGoodsTabs.includes(String(purchaseTabRaw || "")) ? purchaseTabRaw : "goods";
  const purchaseRangeOptions = qtyGiftOnlyGoods ? ["participate"] : ["participate", "exclude"];
  if (scene.isMulti && scene.useRewardRangeTab) purchaseRangeOptions.push("reward");
  const purchaseRangeRaw = AppState.ui.campaignWizard.giftPurchaseRange || "participate";
  const purchaseRange = purchaseRangeOptions.includes(String(purchaseRangeRaw || "")) ? purchaseRangeRaw : "participate";
  AppState.ui.campaignWizard.giftPurchaseRange = purchaseRange;
  const isAll = (gs.multiPurchase && gs.multiPurchase.isAll) ? gs.multiPurchase.isAll : "否";
  /* ── gift: separate participate / exclude tab bars ── */
  const giftParticipateTabDefs = [{ k: "goods", t: "商品" }];
  const giftExcludeTabDefs = qtyGiftOnlyGoods ? [] : [
    { k: "excludeGoods", t: "排除商品" },
    { k: "excludeCategories", t: "排除类别" }
  ];
  const giftParticipateTabsBuy = giftParticipateTabDefs
    .map((x) => `<button class="tabbtn ${x.k === buyTab ? "is-active" : ""}" type="button" data-act="campGiftBuyTab" data-id="${escapeHtml(x.k)}">${escapeHtml(x.t)}</button>`)
    .join("");
  const giftExcludeTabsBuy = giftExcludeTabDefs
    .map((x) => `<button class="tabbtn" type="button" data-act="campGiftBuyExcludeTab" data-id="${escapeHtml(x.k)}">${escapeHtml(x.t)}</button>`)
    .join("");
  const giftParticipateTabsPurchase = giftParticipateTabDefs
    .map((x) => `<button class="tabbtn ${x.k === purchaseTab ? "is-active" : ""}" type="button" data-act="campGiftPurchaseTab" data-id="${escapeHtml(x.k)}">${escapeHtml(x.t)}</button>`)
    .join("");
  const giftExcludeTabsPurchase = giftExcludeTabDefs
    .map((x) => `<button class="tabbtn" type="button" data-act="campGiftPurchaseExcludeTab" data-id="${escapeHtml(x.k)}">${escapeHtml(x.t)}</button>`)
    .join("");
  const giftBuyRangeTabsHtml = `
    <div class="tabbar tabbar--underline" style="margin-bottom:10px;">
      <button class="tabbtn ${buyRange === "participate" ? "is-active" : ""}" type="button" data-act="campGiftBuyRange" data-id="participate">参与范围</button>
      ${(scene.isLadder && !qtyGiftOnlyGoods) ? `<button class="tabbtn ${buyRange === "exclude" ? "is-active" : ""}" type="button" data-act="campGiftBuyRange" data-id="exclude">排除范围</button>` : ""}
      ${scene.isSingle && scene.useRewardRangeTab ? `<button class="tabbtn ${buyRange === "reward" ? "is-active" : ""}" type="button" data-act="campGiftBuyRange" data-id="reward">赠品范围</button>` : ""}
    </div>
  `;
  const giftPurchaseRangeTabsHtml = `
    <div class="tabbar tabbar--underline" style="margin-bottom:10px;">
      <button class="tabbtn ${purchaseRange === "participate" ? "is-active" : ""}" type="button" data-act="campGiftPurchaseRange" data-id="participate">参与范围</button>
      ${qtyGiftOnlyGoods ? "" : `<button class="tabbtn ${purchaseRange === "exclude" ? "is-active" : ""}" type="button" data-act="campGiftPurchaseRange" data-id="exclude">排除范围</button>`}
      ${scene.isMulti && scene.useRewardRangeTab ? `<button class="tabbtn ${purchaseRange === "reward" ? "is-active" : ""}" type="button" data-act="campGiftPurchaseRange" data-id="reward">赠品范围</button>` : ""}
    </div>
  `;
  const giftBuyQueryBarHtml = campaignWizardRenderQueryBar({
    tabsHtml: `<div class="tabbar" id="campGiftBuyTabs">${giftParticipateTabsBuy}</div>`,
    inputHtml: `<input class="input" data-cw="giftSingleScope" data-field="keyword" value="${escapeHtml(String((gs.single && gs.single.keyword) || ""))}" placeholder="按编码、名称查询" />`,
    actionsHtml: `
      <button class="btn btn--primary" type="button" data-act="campKeywordQuery" data-cw="giftSingleScope" data-field="keyword">查询</button>
      <button class="btn" type="button" data-act="campKeywordReset" data-cw="giftSingleScope" data-field="keyword">重置</button>
      <button class="btn" type="button" data-act="campGiftBuyAdd">新增一行</button>
      <button class="btn btn--primary" type="button" data-act="campGiftBuyImport">导入</button>
      <button class="btn" type="button" data-act="campGiftBuySelect">选择</button>
    `
  });
  const giftBuyExcludeQueryBarHtml = campaignWizardRenderQueryBar({
    tabsHtml: `<div class="tabbar" id="campGiftBuyExcludeTabs">${giftExcludeTabsBuy}</div>`,
    inputHtml: `<input class="input" data-cw="giftSingleScope" data-field="keyword" value="${escapeHtml(String((gs.single && gs.single.keyword) || ""))}" placeholder="按编码、名称查询" />`,
    actionsHtml: `
      <button class="btn btn--primary" type="button" data-act="campKeywordQuery" data-cw="giftSingleScope" data-field="keyword">查询</button>
      <button class="btn" type="button" data-act="campKeywordReset" data-cw="giftSingleScope" data-field="keyword">重置</button>
      <button class="btn" type="button" data-act="campGiftBuyExcludeAdd">新增一行</button>
      <button class="btn btn--primary" type="button" data-act="campGiftBuyExcludeImport">导入</button>
      <button class="btn" type="button" data-act="campGiftBuyExcludeSelect">选择</button>
    `
  });
  const giftPurchaseQueryBarHtml = campaignWizardRenderQueryBar({
    tabsHtml: `<div class="tabbar" id="campGiftPurchaseTabs">${giftParticipateTabsPurchase}</div>`,
    inputHtml: `<input class="input" data-cw="giftPurchaseScope" data-field="keyword" value="${escapeHtml(String((gs.multiPurchase && gs.multiPurchase.keyword) || ""))}" placeholder="按编码、名称查询" />`,
    actionsHtml: `
      <button class="btn btn--primary" type="button" data-act="campKeywordQuery" data-cw="giftPurchaseScope" data-field="keyword">查询</button>
      <button class="btn" type="button" data-act="campKeywordReset" data-cw="giftPurchaseScope" data-field="keyword">重置</button>
      <button class="btn" type="button" data-act="campGiftPurchaseAdd">新增一行</button>
      <button class="btn btn--primary" type="button" data-act="campGiftPurchaseImport">导入</button>
      <button class="btn" type="button" data-act="campGiftPurchaseSelect">选择</button>
    `
  });
  const giftPurchaseExcludeQueryBarHtml = campaignWizardRenderQueryBar({
    tabsHtml: `<div class="tabbar" id="campGiftPurchaseExcludeTabs">${giftExcludeTabsPurchase}</div>`,
    inputHtml: `<input class="input" data-cw="giftPurchaseScope" data-field="keyword" value="${escapeHtml(String((gs.multiPurchase && gs.multiPurchase.keyword) || ""))}" placeholder="按编码、名称查询" />`,
    actionsHtml: `
      <button class="btn btn--primary" type="button" data-act="campKeywordQuery" data-cw="giftPurchaseScope" data-field="keyword">查询</button>
      <button class="btn" type="button" data-act="campKeywordReset" data-cw="giftPurchaseScope" data-field="keyword">重置</button>
      <button class="btn" type="button" data-act="campGiftPurchaseExcludeAdd">新增一行</button>
      <button class="btn btn--primary" type="button" data-act="campGiftPurchaseExcludeImport">导入</button>
      <button class="btn" type="button" data-act="campGiftPurchaseExcludeSelect">选择</button>
    `
  });
  return `
    <div class="wizard-step" data-step="${escapeHtml(String(stepNo))}">
      <div class="form">
        <div class="section__title">条件范围</div>
        <div class="form__row">
          <div class="field">
            <div class="field__label">活动互斥</div>
            <div class="checks">
              <label class="check"><input type="radio" name="cwGiftMutex" data-cw="giftScope" data-field="mutex" value="否" ${String(gs.mutex || "否") === "否" ? "checked" : ""} />否</label>
              <label class="check"><input type="radio" name="cwGiftMutex" data-cw="giftScope" data-field="mutex" value="是" ${String(gs.mutex || "否") === "是" ? "checked" : ""} />是</label>
            </div>
            <div class="hint">选择是：直降和折扣商品不参与此类活动。</div>
          </div>
        </div>
        <div class="form__row">
          <div class="field">
            <div class="field__label">满赠方式<span class="req">*</span></div>
            <div class="checks">
              <label class="check"><input type="radio" name="cwGiftMode" data-cw="giftScope" data-field="mode" value="倍数" ${String(gs.mode || "") === "倍数" ? "checked" : ""} />倍数</label>
              <label class="check"><input type="radio" name="cwGiftMode" data-cw="giftScope" data-field="mode" value="阶梯" ${String(gs.mode || "") === "阶梯" ? "checked" : ""} />阶梯</label>
            </div>
            <div class="hint">${escapeHtml(giftModeHint)}</div>
          </div>
          <div class="field">
            <div class="field__label">赠送方式<span class="req">*</span></div>
            ${isQtyGift
              ? `<input class="input" value="${escapeHtml(qtyGiftDisplayWay)}" disabled />`
              : `<div class="checks">
              <label class="check"><input type="radio" name="cwGiftWay" data-cw="giftScope" data-field="giftWay" value="本品" ${String(gs.giftWay || "") === "本品" ? "checked" : ""} ${pr === "多组" ? "disabled" : ""} />本品</label>
              <label class="check"><input type="radio" name="cwGiftWay" data-cw="giftScope" data-field="giftWay" value="非本品" ${String(gs.giftWay || "") === "非本品" ? "checked" : ""} />非本品</label>
            </div>`}
          </div>
        </div>
        <div class="form__row">
          <div class="field">
            <div class="field__label">购买范围<span class="req">*</span></div>
            <div class="checks">
              <label class="check"><input type="radio" name="cwGiftPurchaseRange" data-cw="giftScope" data-field="purchaseRange" value="单组" ${String(pr || "单组") === "单组" ? "checked" : ""} />单组</label>
              <label class="check"><input type="radio" name="cwGiftPurchaseRange" data-cw="giftScope" data-field="purchaseRange" value="多组" ${String(pr || "单组") === "多组" ? "checked" : ""} ${qtyGiftDataWay === "本品" ? "disabled" : ""} />多组</label>
            </div>
          </div>
          <div class="field">
            <div class="field__label">上限数量</div>
            <input class="input" data-cw="giftScope" data-field="capQty" type="number" min="0" step="1" value="${escapeHtml(String(gs.capQty ?? ""))}" placeholder="不限制可留空" />
          </div>
        </div>

        <div class="divider"></div>
        <div id="campGiftBox">
          <div id="campGiftSingleBox">
            <div class="section__title">买赠信息</div>
            ${giftBuyRangeTabsHtml}
            <div id="campGiftBuyParticipateBox" style="${buyRange === "participate" ? "" : "display:none;"}">
              ${giftBuyQueryBarHtml}
              <div id="campGiftBuyTable"></div>
            </div>
            <div id="campGiftBuyExcludeBox" style="${(!qtyGiftOnlyGoods && buyRange === "exclude") ? "" : "display:none;"}">
              ${giftBuyExcludeQueryBarHtml}
              <div id="campGiftBuyExcludeTable"></div>
            </div>
            ${scene.isSingle && scene.useRewardRangeTab ? `<div id="campGiftBuyRewardBox" style="${buyRange === "reward" ? "" : "display:none;"}"><div id="campGiftRewardsTable"></div></div>` : ""}
          </div>

          <div id="campGiftMultiBox">
            <div class="section__title">购买信息</div>
            ${giftPurchaseRangeTabsHtml}
            <div id="campGiftPurchaseParticipateBox" style="${purchaseRange === "participate" ? "" : "display:none;"}">
              ${giftPurchaseQueryBarHtml}
              <div id="campGiftPurchaseTable"></div>
            </div>
            <div id="campGiftPurchaseExcludeBox" style="${purchaseRange === "exclude" ? "" : "display:none;"}">
              ${giftPurchaseExcludeQueryBarHtml}
              <div id="campGiftPurchaseExcludeTable"></div>
            </div>
            ${scene.isMulti && scene.useRewardRangeTab ? `<div id="campGiftPurchaseRewardBox" style="${purchaseRange === "reward" ? "" : "display:none;"}"><div id="campGiftRewardsTable"></div></div>` : ""}
          </div>
        </div>
      </div>
    </div>
  `;
}

function campaignWizardRenderQueryBar({ tabsHtml = "", inputHtml = "", actionsHtml = "" }) {
  return `
    <div class="campaign-querybar">
      <div class="campaign-querybar__tabs">${tabsHtml}</div>
      <div class="campaign-querybar__search">${inputHtml}</div>
      <div class="campaign-querybar__actions toolbar__actions">${actionsHtml}</div>
    </div>
  `;
}

function campaignWizardMainTabsForTemplate(tplSelected, promoType = "") {
  const hasConditionTab = false;
  return [
    { k: "basic", t: "基础信息" },
    { k: "store", t: "门店范围" },
    ...(hasConditionTab ? [{ k: "condition", t: "条件范围" }] : []),
    { k: "goods", t: "商品范围" },
    { k: "burden", t: campaignIsVoucherGiftTemplate(tplSelected) ? "奖励券信息" : "承担规则" }
  ];
}

function campaignWizardStepActionsHtml(currentTab, tabs, mode = "create") {
  const keys = tabs.map((x) => x.k);
  const idx = keys.indexOf(currentTab);
  const hasPrev = idx > 0;
  const hasNext = idx >= 0 && idx < tabs.length - 1;
  const showSubmit = !hasNext && mode === "create";
  return `
    <div class="wizard__footer">
      <div class="wizard__footer-actions">
        <button class="btn" type="button" data-act="campWizPrev" ${hasPrev ? "" : "disabled"}>上一步</button>
        ${showSubmit
          ? `<button class="btn btn--primary" type="button" data-act="campWizSubmit">提交</button>`
          : `<button class="btn btn--primary" type="button" data-act="campWizNext" ${hasNext ? "" : "disabled"}>下一步</button>`}
      </div>
    </div>
  `;
}

function campaignAmountGiftBasicPanelHtml({
  mode = "create",
  draft,
  actualOps = "",
  footerHtml = "",
  readonly = false
} = {}) {
  const d = draft || {};
  const scheduleValue = String(d.scheduleId || "");
  const scheduleDisplay = readonly
    ? `<input class="input" value="${escapeHtml(scheduleValue || "")}" disabled />`
    : `<select class="select" data-cw="root" data-field="scheduleId">${actualOps}</select>`;
  const tplName = "买赠促销";
  const promoTypeText = String(d.activityType || "满减满赠");
  const timeText = (d.startAt && d.endAt) ? `${String(d.startAt)} 至 ${String(d.endAt)}` : "";
  const weekLabels = ["周一", "周二", "周三", "周四", "周五", "周六", "周日"];
  const pickedWeeks = (Array.isArray(d.cycle) ? d.cycle : []).filter((x) => /^周[一二三四五六日]$/.test(String(x)));
  const weekChecks = weekLabels.map((v) => `<label class="check"><input type="checkbox" name="cwCycleWeek" value="${escapeHtml(v)}" ${pickedWeeks.includes(v) ? "checked" : ""} ${readonly ? "disabled" : ""} />${escapeHtml(v)}</label>`).join("");
  const basicInfoHtml = `
    <div class="combo-camp-form__row combo-camp-form__row--2">
      <div class="field">
        <div class="field__label">活动编码</div>
        <input class="input mono" value="${escapeHtml(d.activityNo || "")}" placeholder="自动产生" disabled />
      </div>
      <div class="field">
        <div class="field__label">${readonly ? "" : '<span class="req">*</span>'}活动名称</div>
        <input class="input" ${readonly ? "disabled" : 'data-cw="root" data-field="activitySubject"'} value="${escapeHtml(d.activitySubject || "")}" placeholder="文本框" />
      </div>
    </div>
    <div class="combo-camp-form__row combo-camp-form__row--4">
      <div class="field">
        <div class="field__label">促销模版</div>
        <input class="input" value="${escapeHtml(tplName)}" disabled />
      </div>
      <div class="field">
        <div class="field__label">促销类型</div>
        <input class="input" value="${escapeHtml(promoTypeText)}" disabled />
      </div>
      <div class="field">
        <div class="field__label">${readonly ? "" : '<span class="req">*</span>'}活动模式</div>
        ${readonly
          ? `<input class="input" value="${escapeHtml(d.activityMode || "集团")}" disabled />`
          : `<select class="select" data-cw="root" data-field="activityMode">
              ${["集团", "区域"].map((x) => `<option ${String(d.activityMode || "集团") === x ? "selected" : ""}>${escapeHtml(x)}</option>`).join("")}
            </select>`}
      </div>
      <div class="field">
        <div class="field__label">是否临时调价</div>
        ${readonly
          ? `<input class="input" value="${escapeHtml(String(d.tempPriceAdjust || "否"))}" disabled />`
          : `<div class="checks">
              <label class="check"><input type="radio" name="cwTempAdjust" data-cw="root" data-field="tempPriceAdjust" value="否" ${String(d.tempPriceAdjust || "否") !== "是" ? "checked" : ""} />否</label>
              <label class="check"><input type="radio" name="cwTempAdjust" data-cw="root" data-field="tempPriceAdjust" value="是" ${String(d.tempPriceAdjust || "否") === "是" ? "checked" : ""} />是</label>
            </div>`}
      </div>
      <div class="field">
        <div class="field__label">${(!readonly && String(d.tempPriceAdjust || "否") !== "是") ? '<span class="req">*</span>' : ''}活动档期</div>
        ${scheduleDisplay}
      </div>
    </div>
    ${(!readonly && mode === "create") ? `` : ``}
    <div class="field">
      <div class="field__label">活动说明</div>
      <input class="input" ${readonly ? "disabled" : 'data-cw="root" data-field="desc"'} value="${escapeHtml(d.desc || "")}" placeholder="请输入" />
    </div>
  `;
  const cycleHtml = `
    <div class="field">
      <div class="field__label">${readonly ? "" : '<span class="req">*</span>'}活动时间</div>
      <div class="combo-camp-range">
        <input class="combo-camp-range__input" ${readonly ? "disabled" : 'name="cwTimeRangeText"'} value="${escapeHtml(timeText)}" placeholder="请选择活动开始时间和结束时间" />
        <span class="combo-camp-range__icon" aria-hidden="true"></span>
      </div>
    </div>
    <div class="field">
      <div class="field__label">周</div>
      <div class="checks combo-camp-weekchecks">${weekChecks}</div>
    </div>
  `;
  return `
    <div class="combo-camp-panel">
      ${comboCampaignSectionHtml("基本信息", basicInfoHtml)}
      ${comboCampaignSectionHtml("活动周期", cycleHtml)}
      ${footerHtml}
    </div>
  `;
}

function comboCampaignSectionHtml(title, bodyHtml) {
  return `
    <div class="combo-camp-section">
      <div class="combo-camp-section__title">${escapeHtml(title)}</div>
      <div class="combo-camp-section__body">${bodyHtml}</div>
    </div>
  `;
}

function comboCampaignGoodsCodeValue(value, fallback = 1) {
  const digits = String(value ?? "").replace(/\D/g, "");
  const num = digits || String(fallback || 1);
  return num.padStart(3, "0").slice(-3);
}

function comboCampaignGoodsIsFixedGoodsMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "固定组合" && String(gs.comboScope || "商品") === "商品";
}

function comboCampaignGoodsIsFixedCategoryMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "固定组合" && String(gs.comboScope || "商品") === "类别";
}

function comboCampaignGoodsIsFixedBrandMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "固定组合" && String(gs.comboScope || "商品") === "品牌";
}

function comboCampaignGoodsIsAnyGoodsMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "任选组合" && String(gs.comboScope || "商品") === "商品";
}

function comboCampaignGoodsIsAnyCategoryMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "任选组合" && String(gs.comboScope || "商品") === "类别";
}

function comboCampaignGoodsIsAnyBrandMode(draft = {}) {
  const gs = draft.goodsScope || {};
  return String(gs.comboMode || "固定组合") === "任选组合" && String(gs.comboScope || "商品") === "品牌";
}

function comboCampaignEnsureGoodsScope(draft = {}) {
  draft.goodsScope = draft.goodsScope || {};
  const gs = draft.goodsScope;
  if (!Array.isArray(gs.goods)) gs.goods = [];
  if (!Array.isArray(gs.categories)) gs.categories = [];
  if (!Array.isArray(gs.brands)) gs.brands = [];
  if (!Array.isArray(gs.excludeCategories)) gs.excludeCategories = [];
  if (!Array.isArray(gs.excludeGoods)) gs.excludeGoods = [];
  if (!Array.isArray(gs.comboSettings)) gs.comboSettings = [];
  if (typeof gs.comboMode === "undefined" || gs.comboMode === "") gs.comboMode = "固定组合";
  if (typeof gs.comboScope === "undefined" || gs.comboScope === "") gs.comboScope = "商品";
  if (typeof gs.keyword === "undefined") gs.keyword = "";
  gs.goods.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.goods[idx] = {};
    const row = gs.goods[idx];
    row.comboCode = comboCampaignGoodsCodeValue(row.comboCode, idx + 1);
    if (typeof row.skuCode === "undefined") row.skuCode = "";
    if (typeof row.skuName === "undefined") row.skuName = "";
    if (typeof row.spec === "undefined") row.spec = "";
    if (typeof row.unit === "undefined") row.unit = "";
    if (typeof row.costPrice === "undefined") row.costPrice = "";
    if (typeof row.deductRate === "undefined") row.deductRate = "";
  });
  gs.categories.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.categories[idx] = {};
    const row = gs.categories[idx];
    if (typeof row.catCode === "undefined") row.catCode = "";
    if (typeof row.catName === "undefined") row.catName = "";
  });
  gs.brands.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.brands[idx] = {};
    const row = gs.brands[idx];
    if (typeof row.brandCode === "undefined") row.brandCode = "";
    if (typeof row.brandName === "undefined") row.brandName = "";
    if (typeof row.promoPrice === "undefined") row.promoPrice = "";
    if (typeof row.limitQty === "undefined") row.limitQty = "";
  });
  gs.excludeCategories.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.excludeCategories[idx] = {};
    const row = gs.excludeCategories[idx];
    if (typeof row.catCode === "undefined") row.catCode = "";
    if (typeof row.catName === "undefined") row.catName = "";
  });
  gs.excludeGoods.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.excludeGoods[idx] = {};
    const row = gs.excludeGoods[idx];
    if (typeof row.skuCode === "undefined") row.skuCode = "";
    if (typeof row.barcode === "undefined") row.barcode = "";
    if (typeof row.skuName === "undefined") row.skuName = "";
    if (typeof row.shortName === "undefined") row.shortName = "";
    if (typeof row.spec === "undefined") row.spec = "";
    if (typeof row.unit === "undefined") row.unit = "";
    if (typeof row.price === "undefined") row.price = "";
  });
  gs.comboSettings.forEach((item, idx) => {
    if (!item || typeof item !== "object") gs.comboSettings[idx] = {};
    const row = gs.comboSettings[idx];
    row.comboCode = comboCampaignGoodsCodeValue(row.comboCode, idx + 1);
    if (typeof row.pickQty === "undefined") row.pickQty = "";
    if (typeof row.promoPrice === "undefined") row.promoPrice = "";
    if (typeof row.discountWay === "undefined" || row.discountWay === "") row.discountWay = "倍数";
    if (typeof row.cap === "undefined") row.cap = "";
  });
  if (!gs.comboSettings.length) {
    const uniqueCodes = Array.from(new Set(gs.goods.map((x) => comboCampaignGoodsCodeValue(x.comboCode, 1))));
    if (uniqueCodes.length) gs.comboSettings = uniqueCodes.map((code) => ({ comboCode: code, promoPrice: "", discountWay: "倍数", cap: "" }));
  }
  return gs;
}

function comboCampaignGoodsCodeOptionsHtml(selected = "") {
  const options = Array.from({ length: 10 }).map((_, idx) => comboCampaignGoodsCodeValue(idx + 1, idx + 1));
  return options.map((code) => `<option value="${code}" ${String(selected) === code ? "selected" : ""}>${code}</option>`).join("");
}

function comboCampaignGoodsQueryMeta(goodsScope = {}) {
  const keyword = String(goodsScope.keyword || "").trim().toLowerCase();
  const allRows = (Array.isArray(goodsScope.goods) ? goodsScope.goods : []).map((x, idx) => ({ ...x, __idx: idx }));
  const rows = allRows.filter((x) => {
    if (!keyword) return true;
    const haystack = [x.comboCode, x.skuCode, x.barcode, x.skuName, x.spec, x.unit].join(" ").toLowerCase();
    return haystack.includes(keyword);
  });
  return { keyword, rows };
}

function comboCampaignCategoryActiveTab() {
  const rr = route();
  const uiW = AppState.ui.campaignWizard || {};
  const uiD = AppState.ui.campaignDetail || {};
  const tab = rr.startsWith("/campaigns-detail/")
    ? String(uiD.comboCategoryTab || uiW.comboCategoryTab || "categories")
    : String(uiW.comboCategoryTab || uiD.comboCategoryTab || "categories");
  return ["categories", "excludeCategories", "excludeGoods"].includes(tab) ? tab : "categories";
}

function comboCampaignScopePickKey(tab) {
  return tab === "excludeGoods" ? "comboExcludeGoodsPicked" : "comboCategoryPicked";
}

function comboCampaignCategoryQueryMeta(goodsScope = {}, tab = "categories") {
  const keyword = String(goodsScope.keyword || "").trim().toLowerCase();
  const source = Array.isArray(goodsScope[tab]) ? goodsScope[tab] : [];
  const rows = source.map((x, idx) => ({ ...x, __idx: idx })).filter((x) => {
    if (!keyword) return true;
    const haystack = tab === "excludeGoods"
      ? [x.skuCode, x.skuName, x.barcode, x.spec].join(" ").toLowerCase()
      : [x.catCode, x.catName].join(" ").toLowerCase();
    return haystack.includes(keyword);
  });
  return { keyword, rows };
}

function comboCampaignBrandActiveTab() {
  const rr = route();
  const uiW = AppState.ui.campaignWizard || {};
  const uiD = AppState.ui.campaignDetail || {};
  const tab = rr.startsWith("/campaigns-detail/")
    ? String(uiD.comboBrandTab || uiW.comboBrandTab || "brands")
    : String(uiW.comboBrandTab || uiD.comboBrandTab || "brands");
  return ["brands", "excludeGoods"].includes(tab) ? tab : "brands";
}

function comboCampaignBrandPickKey(tab) {
  return tab === "excludeGoods" ? "comboBrandExcludeGoodsPicked" : "comboBrandPicked";
}

function comboCampaignBrandQueryMeta(goodsScope = {}, tab = "brands") {
  const keyword = String(goodsScope.keyword || "").trim().toLowerCase();
  const source = Array.isArray(goodsScope[tab]) ? goodsScope[tab] : [];
  const rows = source.map((x, idx) => ({ ...x, __idx: idx })).filter((x) => {
    if (!keyword) return true;
    const haystack = tab === "excludeGoods"
      ? [x.skuCode, x.skuName, x.barcode, x.spec].join(" ").toLowerCase()
      : [x.brandCode, x.brandName].join(" ").toLowerCase();
    return haystack.includes(keyword);
  });
  return { keyword, rows };
}

