          <div class="preview-item"><div class="preview-item__k" style="font-weight:800">应付金额</div><div class="preview-item__v mono" style="font-weight:900;font-size:16px;color:#ea580c">¥ ${st.settlementAmount.toFixed(2)}</div></div>
